from pm_version_out
where del_flag = '0' and sys_name = #{sysName} and version_type = #{versionType}

select version_code
from pm_version_out
where del_flag = '0' and sys_name = #{sysName} and version_type = #{versionType}
  and out_version = #{outVersion}
order by version_code desc limit 1

