select t.task_id, t.software_demand_no as task_no, t.task_name, t.demand_name,
       p.project_name as prj_name
from pm_task t
left join pm_project p on t.project_id = p.project_id
where t.production_year = #{productionYear}
  and t.batch_id = #{batchId}
  and t.product = #{product}
order by t.software_demand_no desc
